export const getIngestSlackWebhookUrl = () => {




  return `/api/webhooks/slack`
}

/**
 * @summary Receive Slack webhook events
 */
export const ingestSlackWebhook = async (webhookPayload: WebhookPayload, options?: RequestInit): Promise<WebhookAck> => {

  return customFetch<WebhookAck>(getIngestSlackWebhookUrl(),
  {
    ...options,
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(
      webhookPayload,)
  }
);}




